package main

import (
	"database/sql"
	"fmt"
	"log"
	"os"
	"time"

	_ "github.com/lib/pq"
)

// DBConfig holds database connection configuration loaded from environment variables.
type DBConfig struct {
	Host     string
	Port     string
	Database string
	User     string
	Password string
	SSLMode  string
}

// LoadDBConfig reads database configuration from environment variables.
// All sensitive values must be provided via environment variables or a secret manager.
func LoadDBConfig() (*DBConfig, error) {
	cfg := &DBConfig{
		Host:     getEnvOrDefault("DB_HOST", "localhost"),
		Port:     getEnvOrDefault("DB_PORT", "5432"),
		Database: getEnvRequired("DB_NAME"),
		User:     getEnvRequired("DB_USER"),
		Password: getEnvRequired("DB_PASSWORD"),
		SSLMode:  getEnvOrDefault("DB_SSLMODE", "disable"),
	}

	if cfg.Database == "" || cfg.User == "" || cfg.Password == "" {
		return nil, fmt.Errorf(
			"missing required database environment variables: DB_NAME, DB_USER, and DB_PASSWORD must be set\n" +
				"Example:\n" +
				"  export DB_NAME=demo_db\n" +
				"  export DB_USER=postgres\n" +
				"  export DB_PASSWORD=<your-password>\n" +
				"  go run main.go",
		)
	}

	return cfg, nil
}

func getEnvOrDefault(key, defaultValue string) string {
	if value, exists := os.LookupEnv(key); exists {
		return value
	}
	return defaultValue
}

func getEnvRequired(key string) string {
	value, exists := os.LookupEnv(key)
	if !exists || value == "" {
		return ""
	}
	return value
}

// ConnectDB establishes a connection to the PostgreSQL database using
// configuration from environment variables.
func ConnectDB() (*sql.DB, error) {
	cfg, err := LoadDBConfig()
	if err != nil {
		return nil, fmt.Errorf("failed to load database config: %w", err)
	}

	connStr := fmt.Sprintf(
		"host=%s port=%s dbname=%s user=%s password=%s sslmode=%s",
		cfg.Host, cfg.Port, cfg.Database, cfg.User, cfg.Password, cfg.SSLMode,
	)

	// Clear password from config struct after building connection string
	cfg.Password = ""

	db, err := sql.Open("postgres", connStr)
	if err != nil {
		return nil, fmt.Errorf("failed to open database connection: %w", err)
	}

	// Configure connection pool
	db.SetMaxOpenConns(25)
	db.SetMaxIdleConns(5)
	db.SetConnMaxLifetime(5 * time.Minute)
	db.SetConnMaxIdleTime(1 * time.Minute)

	// Verify the connection is working
	if err := db.Ping(); err != nil {
		db.Close()
		return nil, fmt.Errorf("failed to ping database: %w", err)
	}

	log.Println("Successfully connected to the database")
	return db, nil
}

func main() {
	db, err := ConnectDB()
	if err != nil {
		log.Fatalf("Database connection failed: %v", err)
	}
	defer db.Close()

	// Verify connection with a simple query
	var result int
	err = db.QueryRow("SELECT 1").Scan(&result)
	if err != nil {
		log.Fatalf("Query failed: %v", err)
	}

	log.Printf("Demo database connection verified successfully (result=%d)", result)
}